// Стало (работает в Node.js ≥ 10):
const fs = require('node:fs/promises');
const path = require('node:path');
const SVGFixer = require('oslllo-svg-fixer');

const options = {
    showProgressBar: true,
    throwIfDestinationDoesNotExist: false,
};

const incomingDir = 'src/assets/icons-new';
const fixedDir = 'src/assets/fixed';
const iconsDir = 'src/assets/icons';

function movePathFillToSvg(svgContent) {
    const pathFillMatch = svgContent.match(/<path\b[^>]*\sfill="([^"]+)"[^>]*>/i);

    if (!pathFillMatch) {
        return svgContent;
    }

    const pathFill = pathFillMatch[1];

    const withSvgFill = svgContent.replace(
        /<svg\b([^>]*)>/i,
        (fullMatch, attrs) => {
            if (/\sfill="/i.test(attrs)) {
                return fullMatch.replace(/\sfill="[^"]*"/i, ` fill="${pathFill}"`);
            }

            return `<svg${attrs} fill="${pathFill}">`;
        }
    );

    return withSvgFill.replace(
        /<path\b([^>]*)>/i,
        (fullMatch, attrs) => `<path${attrs.replace(/\sfill="[^"]*"/i, '')}>`
    );
}

async function postProcessFixedSvgs() {
    const fileNames = await fs.readdir(fixedDir);
    const svgFileNames = fileNames.filter((fileName) => fileName.toLowerCase().endsWith('.svg'));

    await Promise.all(
        svgFileNames.map(async (fileName) => {
            const filePath = path.join(fixedDir, fileName);
            const content = await fs.readFile(filePath, 'utf8');
            const updatedContent = movePathFillToSvg(content);

            if (updatedContent !== content) {
                await fs.writeFile(filePath, updatedContent, 'utf8');
            }
        })
    );

    return svgFileNames;
}

async function getSvgFiles(dirPath) {
    const fileNames = await fs.readdir(dirPath);
    return fileNames.filter((fileName) => fileName.toLowerCase().endsWith('.svg'));
}

async function removeFiles(dirPath, fileNames) {
    await Promise.all(
        fileNames.map((fileName) => fs.rm(path.join(dirPath, fileName), { force: true }))
    );
}

async function moveFiles(sourceDir, destinationDir, fileNames) {
    await Promise.all(
        fileNames.map(async (fileName) => {
            await fs.rename(
                path.join(sourceDir, fileName),
                path.join(destinationDir, fileName)
            );
        })
    );
}

async function run() {
    await fs.mkdir(incomingDir, { recursive: true });
    await fs.mkdir(fixedDir, { recursive: true });
    await fs.mkdir(iconsDir, { recursive: true });

    const incomingSvgFiles = await getSvgFiles(incomingDir);

    if (!incomingSvgFiles.length) {
        console.log('No new icons found in src/assets/icons-new');
        return;
    }

    await SVGFixer(incomingDir, fixedDir, options).fix();
    const fixedSvgFiles = await postProcessFixedSvgs();

    await moveFiles(fixedDir, iconsDir, fixedSvgFiles);
    await removeFiles(incomingDir, incomingSvgFiles);

    console.log(`Processed ${fixedSvgFiles.length} icon(s)`);
}

run().catch((err) => {
    throw err;
});
